     1→use std::str::FromStr;
     2→
     3→use anyhow::Result;
     4→use chrono::{TimeZone, Utc};
     5→use clap::Parser;
     6→use solana_client::{rpc_client::RpcClient, rpc_config::RpcTransactionConfig};
     7→use solana_sdk::{commitment_config::CommitmentConfig, pubkey::Pubkey, signature::Signature};
     8→use solana_transaction_status::{
     9→    option_serializer::OptionSerializer, EncodedTransaction, UiMessage, UiTransactionEncoding,
    10→};
    11→use tabled::{settings::Style, Table, Tabled};
    12→
    13→/// Light Registry program ID
    14→const REGISTRY_PROGRAM_ID: &str = "REDACTED";
    15→
    16→#[derive(Debug, Parser)]
    17→pub struct Options {
    18→    /// Time window in minutes to fetch failed transactions (default: 10)
    19→    #[clap(long, default_value_t = 10)]
    20→    minutes: u64,
    21→
    22→    /// Network to use (mainnet, devnet, local)
    23→    #[clap(long, default_value = "mainnet")]
    24→    network: String,
    25→
    26→    /// Custom RPC URL (overrides network param)
    27→    #[clap(long)]
    28→    rpc_url: Option<String>,
    29→
    30→    /// Show detailed logs for each failed transaction
    31→    #[clap(long, short, default_value_t = false)]
    32→    verbose: bool,
    33→}
    34→
    35→#[derive(Tabled)]
    36→struct FailedTxRow {
    37→    #[tabled(rename = "Signature")]
    38→    signature: String,
    39→    #[tabled(rename = "Time")]
    40→    time: String,
    41→    #[tabled(rename = "Error")]
    42→    error: String,
    43→}
    44→
    45→fn network_to_url(network: &str) -> String {
    46→    match network {
    47→        "mainnet" => "https://api.mainnet-beta.solana.com".to_string(),
    48→        "devnet" => "https://api.devnet.solana.com".to_string(),
    49→        "testnet" => "https://api.testnet.solana.com".to_string(),
    50→        "local" | "localnet" => "http://localhost:8899".to_string(),
    51→        custom => custom.to_string(),
    52→    }
    53→}
    54→
    55→fn format_timestamp(block_time: Option<i64>) -> String {
    56→    match block_time {
    57→        Some(ts) => Utc
    58→            .timestamp_opt(ts, 0)
    59→            .single()
    60→            .map(|dt| dt.format("%Y-%m-%d %H:%M:%S").to_string())
    61→            .unwrap_or_else(|| "Invalid timestamp".to_string()),
    62→        None => "N/A".to_string(),
    63→    }
    64→}
    65→
    66→fn shorten_signature(sig: &str) -> String {
    67→    if sig.len() > 12 {
    68→        format!("{}...{}", &sig[..5], &sig[sig.len() - 4..])
    69→    } else {
    70→        sig.to_string()
    71→    }
    72→}
    73→
    74→/// Extract error message from logs by looking for "Error Message:" pattern
    75→fn extract_error_from_logs(logs: &[String]) -> Option<String> {
    76→    for log in logs {
    77→        // Look for AnchorError pattern: "Error Message: <message>."
    78→        if let Some(pos) = log.find("Error Message:") {
    79→            let msg_start = pos + "Error Message:".len();
    80→            let msg = log[msg_start..].trim();
    81→            // Remove trailing period if present
    82→            let msg = msg.trim_end_matches('.');
    83→            return Some(msg.to_string());
    84→        }
    85→    }
    86→    None
    87→}
    88→
    89→pub async fn fetch_failed_txs(opts: Options) -> Result<()> {
    90→    let rpc_url = opts
    91→        .rpc_url
    92→        .unwrap_or_else(|| network_to_url(&opts.network));
    93→
    94→    println!("Fetching failed transactions from Light Registry program");
    95→    println!("RPC: {}", rpc_url);
    96→    println!("Time window: {} minutes", opts.minutes);
    97→    println!();
    98→
    99→    let client = RpcClient::new_with_commitment(rpc_url, CommitmentConfig::confirmed());
   100→    let program_id = Pubkey::from_str(REGISTRY_PROGRAM_ID)?;
   101→
   102→    let cutoff_timestamp = Utc::now().timestamp() - (opts.minutes as i64 * 60);
   103→
   104→    // Fetch signatures for the program
   105→    let signatures = client.get_signatures_for_address(&program_id)?;
   106→
   107→    // Filter to failed transactions within the time window
   108→    let failed_txs: Vec<_> = signatures
   109→        .into_iter()
   110→        .filter(|sig_info| {
   111→            // Must have an error
   112→            if sig_info.err.is_none() {
   113→                return false;
   114→            }
   115→            // Must be within time window
   116→            if let Some(block_time) = sig_info.block_time {
   117→                block_time >= cutoff_timestamp
   118→            } else {
   119→                false
   120→            }
   121→        })
   122→        .collect();
   123→
   124→    if failed_txs.is_empty() {
   125→        println!(
   126→            "No failed transactions found in the last {} minutes.",
   127→            opts.minutes
   128→        );
   129→        return Ok(());
   130→    }
   131→
   132→    println!(
   133→        "Found {} failed transaction(s) in the last {} minutes:\n",
   134→        failed_txs.len(),
   135→        opts.minutes
   136→    );
   137→
   138→    // Collect detailed info for each failed transaction
   139→    struct TxDetails {
   140→        signature: String,
   141→        block_time: Option<i64>,
   142→        error_code: String,
   143→        error_message: String,
   144→        logs: Vec<String>,
   145→        accounts: Vec<String>,
   146→    }
   147→
   148→    let mut tx_details: Vec<TxDetails> = Vec::new();
   149→
   150→    for sig_info in &failed_txs {
   151→        let signature = Signature::from_str(&sig_info.signature)?;
   152→        let error_code = sig_info
   153→            .err
   154→            .as_ref()
   155→            .map(|e| format!("{:?}", e))
   156→            .unwrap_or_else(|| "Unknown".to_string());
   157→
   158→        let (error_message, logs, accounts) = match client.get_transaction_with_config(
   159→            &signature,
   160→            RpcTransactionConfig {
   161→                encoding: Some(UiTransactionEncoding::Json),
   162→                commitment: Some(CommitmentConfig::confirmed()),
   163→                max_supported_transaction_version: Some(0),
   164→            },
   165→        ) {
   166→            Ok(tx) => {
   167→                // Extract account keys from transaction
   168→                let accounts = match &tx.transaction.transaction {
   169→                    EncodedTransaction::Json(ui_tx) => match &ui_tx.message {
   170→                        UiMessage::Parsed(msg) => {
   171→                            msg.account_keys.iter().map(|k| k.pubkey.clone()).collect()
   172→                        }
   173→                        UiMessage::Raw(msg) => msg.account_keys.clone(),
   174→                    },
   175→                    _ => vec![],
   176→                };
   177→
   178→                if let Some(meta) = tx.transaction.meta {
   179→                    if let OptionSerializer::Some(logs) = meta.log_messages {
   180→                        let error_msg =
   181→                            extract_error_from_logs(&logs).unwrap_or_else(|| error_code.clone());
   182→                        (error_msg, logs, accounts)
   183→                    } else {
   184→                        (error_code.clone(), vec![], accounts)
   185→                    }
   186→                } else {
   187→                    (error_code.clone(), vec![], accounts)
   188→                }
   189→            }
   190→            Err(_) => (error_code.clone(), vec![], vec![]),
   191→        };
   192→
   193→        tx_details.push(TxDetails {
   194→            signature: sig_info.signature.clone(),
   195→            block_time: sig_info.block_time,
   196→            error_code,
   197→            error_message,
   198→            logs,
   199→            accounts,
   200→        });
   201→    }
   202→
   203→    // Build table rows
   204→    let rows: Vec<FailedTxRow> = tx_details
   205→        .iter()
   206→        .map(|tx| FailedTxRow {
   207→            signature: shorten_signature(&tx.signature),
   208→            time: format_timestamp(tx.block_time),
   209→            error: tx.error_message.clone(),
   210→        })
   211→        .collect();
   212→
   213→    let table = Table::new(&rows).with(Style::rounded()).to_string();
   214→    println!("{}", table);
   215→
   216→    // Print one full tx log for each unique error code
   217→    println!("\n--- Sample Logs per Error Type ---\n");
   218→    let mut seen_errors: std::collections::HashSet<String> = std::collections::HashSet::new();
   219→    for tx in &tx_details {
   220→        if !seen_errors.contains(&tx.error_code) && !tx.logs.is_empty() {
   221→            seen_errors.insert(tx.error_code.clone());
   222→            println!("Error Code: {}", tx.error_code);
   223→            println!("Error Message: {}", tx.error_message);
   224→            println!("Sample Signature: {}", tx.signature);
   225→            if !tx.accounts.is_empty() {
   226→                println!("Accounts ({}):", tx.accounts.len());
   227→                for (i, account) in tx.accounts.iter().enumerate() {
   228→                    println!("  [{}] {}", i, account);
   229→                }
   230→            }
   231→            println!("Logs:");
   232→            for log in &tx.logs {
   233→                println!("  {}", log);
   234→            }
   235→            println!("{}", "-".repeat(80));
   236→        }
   237→    }
   238→
   239→    // Print full details for each failed transaction (only if verbose)
   240→    if opts.verbose {
   241→        println!("\n--- All Failed Transactions (Verbose) ---\n");
   242→
   243→        for tx in &tx_details {
   244→            println!("Signature: {}", tx.signature);
   245→            println!("Time: {}", format_timestamp(tx.block_time));
   246→            println!("Error Code: {}", tx.error_code);
