use clap::{Parser, ValueEnum};

mod bench;
mod close_buffer;
mod create_batch_address_tree;
mod create_batch_state_tree;
mod create_compressible_config;
mod create_ctoken_account;
mod create_state_tree;
mod create_update_protocol_config_ix;
