    65→    match &cli.command {
    66→        Commands::Start(args) => {
    67→            let config = Arc::new(ForesterConfig::new_for_start(args)?);
    68→
    69→            if config.general_config.enable_metrics {
    70→                register_metrics();
    71→            }
    72→
    73→            let (shutdown_sender_service, shutdown_receiver_service) = oneshot::channel();
    74→            let (work_report_sender, mut work_report_receiver) = mpsc::channel(100);
    75→
    76→            tokio::spawn(async move {
    77→                while let Some(report) = work_report_receiver.recv().await {
    78→                    debug!("Work Report: {:?}", report);
    79→                }
    80→            });
    81→
    82→            let rpc_rate_limiter = config
    83→                .external_services
    84→                .rpc_rate_limit
    85→                .map(RateLimiter::new);
    86→            let send_tx_limiter = config
    87→                .external_services
    88→                .send_tx_rate_limit
    89→                .map(RateLimiter::new);
    90→
    91→            let mut shutdown_sender_compressible: Option<tokio::sync::broadcast::Sender<()>> = None;
    92→            let mut shutdown_sender_bootstrap: Option<oneshot::Sender<()>> = None;
    93→
    94→            let preconfigured_trackers = if config.compressible_config.is_some() {
    95→                let (sender, receiver) = tokio::sync::broadcast::channel(1);
    96→                let (bootstrap_sender, bootstrap_receiver) = oneshot::channel();
    97→                shutdown_sender_compressible = Some(sender);
    98→                shutdown_sender_bootstrap = Some(bootstrap_sender);
    99→                Some(
   100→                    initialize_compressible_trackers(
   101→                        config.clone(),
   102→                        Some(receiver),
   103→                        Some(bootstrap_receiver),
   104→                    )
   105→                    .await?,
   106→                )
   107→            } else {
   108→                None
   109→            };
   110→
   111→            let compressible_state = preconfigured_trackers.as_ref().and_then(|trackers| {
   112→                if trackers.ctoken_tracker.is_none()
   113→                    && trackers.pda_tracker.is_none()
   114→                    && trackers.mint_tracker.is_none()
   115→                {
   116→                    None
   117→                } else {
   118→                    Some(CompressibleDashboardState {
   119→                        ctoken_tracker: trackers.ctoken_tracker.clone(),
   120→                        pda_tracker: trackers.pda_tracker.clone(),
   121→                        mint_tracker: trackers.mint_tracker.clone(),
   122→                    })
   123→                }
   124→            });
   125→
   126→            let rpc_url_for_api: String = config.external_services.rpc_url.to_string();
   127→            let run_id = generate_run_id();
   128→            let api_server_handle = spawn_api_server(ApiServerConfig {
   129→                run_id: Arc::<str>::from(run_id.clone()),
   130→                rpc_url: rpc_url_for_api,
   131→                port: args.api_server_port,
   132→                allow_public_bind: args.api_server_public_bind,
   133→                compressible_state,
   134→                prometheus_url: args.prometheus_url.clone(),
   135→                helius_rpc: args.helius_rpc,
   136→                forester_api_urls: Vec::new(),
   137→            })?;
   138→
   139→            spawn_shutdown_handler(
   140→                shutdown_sender_service,
   141→                Some(move || {
   142→                    if let Some(sender) = shutdown_sender_compressible {
   143→                        let _ = sender.send(());
   144→                    }
   145→                    if let Some(sender) = shutdown_sender_bootstrap {
   146→                        let _ = sender.send(());
   147→                    }
   148→                    api_server_handle.shutdown();
   149→                }),
   150→            );
   151→
   152→            run_pipeline_with_run_id::<LightClient>(
   153→                config,
   154→                rpc_rate_limiter,
   155→                send_tx_limiter,
   156→                shutdown_receiver_service,
   157→                None,
   158→                None,
   159→                work_report_sender,
   160→                run_id,
   161→                preconfigured_trackers,
   162→            )
   163→            .await?
   164→        }
   165→        Commands::Status(args) => {
   166→            forester_status::fetch_forester_status(args).await?;
   167→        }
   168→        Commands::Health(args) => {
   169→            let result = run_health_check(args).await?;
   170→            if !result && args.exit_on_failure {
   171→                std::process::exit(1);
   172→            }
   173→        }
   174→        Commands::Dashboard(args) => {
   175→            tracing::info!(
   176→                event = "dashboard_server_starting",
   177→                port = args.port,
   178→                "Starting standalone dashboard API server"
   179→            );
   180→            let run_id = generate_run_id();
   181→            let api_server_handle = spawn_api_server(ApiServerConfig {
   182→                run_id: Arc::<str>::from(run_id),
   183→                rpc_url: args.rpc_url.clone(),
   184→                port: args.port,
   185→                allow_public_bind: args.public_bind,
   186→                compressible_state: None,
   187→                prometheus_url: args.prometheus_url.clone(),
   188→                helius_rpc: false,
   189→                forester_api_urls: args.forester_api_urls.clone(),
   190→            })?;
   191→
   192→            // Block until Ctrl+C
   193→            if let Err(e) = ctrl_c().await {
   194→                tracing::error!(
   195→                    event = "dashboard_ctrlc_listener_failed",
   196→                    error = %e,
   197→                    "Failed to listen for Ctrl+C"
   198→                );
   199→            }
   200→            tracing::info!(
   201→                event = "dashboard_shutdown_signal_received",
   202→                "Received Ctrl+C, shutting down dashboard API server"
   203→            );
   204→            api_server_handle.shutdown();
   205→        }
   206→    }
   207→    Ok(())
   208→}
