   122→/// Get forester status with optional group authority filtering.
   123→///
   124→/// # Arguments
   125→/// * `rpc_url` - RPC URL to connect to
   126→/// * `filter_by_group_authority` - If true, filter trees by protocol group authority.
   127→///   If false, show all trees without filtering.
   128→pub async fn get_forester_status(rpc_url: &str) -> crate::Result<ForesterStatus> {
   129→    get_forester_status_with_options(rpc_url, true).await
   130→}
   131→
   132→/// Get forester status with explicit control over group authority filtering.
   133→pub async fn get_forester_status_with_options(
   134→    rpc_url: &str,
   135→    filter_by_group_authority: bool,
   136→) -> crate::Result<ForesterStatus> {
   137→    let rpc = LightClient::new(LightClientConfig {
   138→        url: rpc_url.to_string(),
   139→        photon_url: None,
   140→        commitment_config: None,
   141→        fetch_active_tree: false,
   142→    })
   143→    .await
   144→    .context("Failed to create LightClient")?;
   145→
   146→    // Phase 1: Fetch registry accounts and slot in parallel
   147→    let (registry_result, slot_result) =
   148→        tokio::join!(fetch_registry_accounts_filtered(&rpc), rpc.get_slot(),);
   149→
   150→    let (forester_epoch_pdas, _epoch_pdas, protocol_config_pdas) = registry_result?;
   151→    let slot = slot_result.context("Failed to get slot")?;
   152→
   153→    let protocol_config_pda = protocol_config_pdas
   154→        .first()
   155→        .cloned()
   156→        .context("No ProtocolConfigPda found in registry program accounts")?;
   157→
   158→    let current_active_epoch = protocol_config_pda.config.get_current_active_epoch(slot)?;
   159→    let latest_register_epoch = protocol_config_pda.config.get_latest_register_epoch(slot)?;
   160→
   161→    let active_epoch_progress = protocol_config_pda
   162→        .config
   163→        .get_current_active_epoch_progress(slot);
   164→    let active_phase_length = protocol_config_pda.config.active_phase_length;
   165→    let active_epoch_progress_percentage =
   166→        active_epoch_progress as f64 / active_phase_length as f64 * 100f64;
   167→
   168→    let hours_until_next_epoch =
   169→        active_phase_length.saturating_sub(active_epoch_progress) * 460 / 1000 / 3600;
   170→
   171→    // Registration is relaxed: foresters can register at any time during the epoch,
   172→    // so registration is always open for the latest register epoch.
   173→    let registration_is_open = protocol_config_pda
   174→        .config
   175→        .is_registration_phase(slot)
   176→        .is_ok();
   177→
   178→    // If registration is closed, show the next epoch as the registration target
   179→    let registration_phase_length = protocol_config_pda.config.registration_phase_length;
   180→    let current_registration_epoch = if registration_is_open {
   181→        latest_register_epoch
   182→    } else {
   183→        latest_register_epoch + 1
   184→    };
   185→
   186→    let slots_until_next_registration = if registration_is_open {
   187→        // Slots until current registration closes
   188→        let epoch_progress = protocol_config_pda
   189→            .config
   190→            .get_latest_register_epoch_progress(slot)
   191→            .unwrap_or(0);
   192→        registration_phase_length.saturating_sub(epoch_progress)
   193→    } else {
   194→        // Slots until next epoch's registration opens
   195→        active_phase_length.saturating_sub(
   196→            protocol_config_pda
   197→                .config
   198→                .get_latest_register_epoch_progress(slot)
   199→                .unwrap_or(0),
   200→        )
   201→    };
   202→    let hours_until_next_registration = slots_until_next_registration * 460 / 1000 / 3600;
   203→
   204→    // Collect forester authorities for both epochs
   205→    let active_forester_authorities: Vec<Pubkey> = forester_epoch_pdas
   206→        .iter()
   207→        .filter(|pda| pda.epoch == current_active_epoch)
   208→        .map(|pda| pda.authority)
   209→        .collect();
   210→
   211→    let registration_forester_authorities: Vec<Pubkey> = forester_epoch_pdas
   212→        .iter()
   213→        .filter(|pda| pda.epoch == current_registration_epoch)
   214→        .map(|pda| pda.authority)
   215→        .collect();
   216→
   217→    // Fetch all forester balances in one batch call using Rpc trait
   218→    let all_forester_pubkeys: Vec<Pubkey> = active_forester_authorities
   219→        .iter()
   220→        .chain(registration_forester_authorities.iter())
   221→        .cloned()
   222→        .collect();
   223→
   224→    let forester_balances = fetch_forester_balances(&rpc, &all_forester_pubkeys).await;
   225→
   226→    // Build ForesterInfo with balances
   227→    let active_epoch_foresters: Vec<ForesterInfo> = active_forester_authorities
   228→        .iter()
   229→        .map(|authority| {
   230→            let balance = forester_balances.get(authority).copied().flatten();
   231→            ForesterInfo {
   232→                authority: authority.to_string(),
   233→                balance_sol: balance,
   234→            }
   235→        })
   236→        .collect();
   237→
   238→    let registration_epoch_foresters: Vec<ForesterInfo> = registration_forester_authorities
   239→        .iter()
   240→        .map(|authority| {
   241→            let balance = forester_balances.get(authority).copied().flatten();
   242→            ForesterInfo {
   243→                authority: authority.to_string(),
   244→                balance_sol: balance,
   245→            }
   246→        })
   247→        .collect();
   248→
   249→    // Phase 2: Fetch trees using existing optimized method
   250→    let mut trees = match fetch_trees(&rpc).await {
   251→        Ok(trees) => trees,
   252→        Err(e) => {
   253→            warn!("Failed to fetch trees: {:?}", e);
   254→            return Ok(ForesterStatus {
   255→                slot,
   256→                current_active_epoch,
   257→                current_registration_epoch,
   258→                active_epoch_progress,
   259→                active_phase_length,
   260→                active_epoch_progress_percentage,
   261→                hours_until_next_epoch,
   262→                registration_is_open,
   263→                slots_until_next_registration,
   264→                hours_until_next_registration,
   265→                active_epoch_foresters,
   266→                registration_epoch_foresters,
   267→                trees: vec![],
   268→                current_light_slot: None,
   269→                light_slot_length: protocol_config_pda.config.slot_length,
   270→                slots_until_next_light_slot: None,
   271→                total_light_slots: 0,
   272→                total_trees: 0,
   273→                active_trees: 0,
   274→                rolled_over_trees: 0,
   275→                total_pending_batches: 0,
   276→                total_pending_items: 0,
   277→                aggregate_queue_stats: AggregateQueueStats {
   278→                    state_v1_total_pending: 0,
   279→                    state_v2_input_pending: 0,
   280→                    state_v2_output_pending: 0,
   281→                    address_v1_total_pending: 0,
   282→                    address_v2_input_pending: 0,
   283→                    state_v2_input_pending_batches: 0,
   284→                    state_v2_output_pending_batches: 0,
   285→                    address_v2_input_pending_batches: 0,
   286→                },
   287→            });
   288→        }
   289→    };
   290→
   291→    // Filter trees by protocol group authority if enabled
   292→    if filter_by_group_authority {
   293→        match fetch_protocol_group_authority(&rpc, "status").await {
   294→            Ok(group_authority) => {
   295→                let before_count = trees.len();
   296→                trees.retain(|tree| tree.owner == group_authority);
   297→                debug!(
   298→                    "Group authority filtering enabled: filtered by {} ({} -> {} trees)",
   299→                    group_authority,
   300→                    before_count,
   301→                    trees.len()
   302→                );
   303→            }
   304→            Err(e) => {
   305→                warn!(
   306→                    "Group authority filtering enabled but fetch failed: {:?}. Showing all trees.",
   307→                    e
   308→                );
   309→            }
   310→        }
   311→    } else {
   312→        debug!(
   313→            "Group authority filtering disabled, showing all {} trees",
   314→            trees.len()
   315→        );
   316→    }
   317→
   318→    // Phase 3: Batch fetch all tree and queue accounts using Rpc trait
   319→    let mut tree_statuses = fetch_tree_statuses_batched(&rpc, &trees).await;
   320→
   321→    // Phase 4: Compute light slot info and forester assignments
   322→    let light_slot_length = protocol_config_pda.config.slot_length;
   323→    let mut current_light_slot: Option<u64> = None;
   324→    let mut slots_until_next_light_slot: Option<u64> = None;
   325→    let mut total_light_slots: u64 = 0;
   326→
   327→    let active_epoch_forester_pdas: Vec<&ForesterEpochPda> = forester_epoch_pdas
   328→        .iter()
   329→        .filter(|pda| pda.epoch == current_active_epoch)
   330→        .collect();
   331→
   332→    // Build authority -> index map for schedule
   333→    let authority_to_index: HashMap<String, usize> = active_epoch_foresters
   334→        .iter()
   335→        .enumerate()
   336→        .map(|(i, f)| (f.authority.clone(), i))
   337→        .collect();
   338→
   339→    if !active_epoch_forester_pdas.is_empty() {
   340→        if let Some(total_epoch_weight) = active_epoch_forester_pdas
   341→            .first()
   342→            .and_then(|pda| pda.total_epoch_weight)
   343→            .filter(|&w| w > 0)
   344→        {
   345→            let epoch_phases = get_epoch_phases(&protocol_config_pda.config, current_active_epoch);
   346→
   347→            if light_slot_length > 0 {
   348→                total_light_slots = epoch_phases.active.length() / light_slot_length;
   349→
   350→                // Compute current light slot if in active phase
   351→                if slot >= epoch_phases.active.start && slot < epoch_phases.active.end {
   352→                    let current_light_slot_index =
   353→                        (slot - epoch_phases.active.start) / light_slot_length;
   354→                    current_light_slot = Some(current_light_slot_index);
   355→
   356→                    // Calculate slots until next light slot
   357→                    let next_light_slot_start = epoch_phases.active.start
   358→                        + (current_light_slot_index + 1) * light_slot_length;
   359→                    slots_until_next_light_slot = Some(next_light_slot_start.saturating_sub(slot));
   360→                }
   361→
   362→                // Build full schedule for each tree
   363→                for status in &mut tree_statuses {
   364→                    // V2 trees use the merkle tree pubkey as seed for eligibility,
   365→                    // while V1 trees use the queue pubkey
   366→                    let is_v2_tree =
   367→                        status.tree_type == "StateV2" || status.tree_type == "AddressV2";
   368→                    let seed_pubkey_str = if is_v2_tree {
   369→                        &status.merkle_tree
   370→                    } else {
   371→                        &status.queue
   372→                    };
   373→                    let seed_pubkey: Pubkey = match seed_pubkey_str.parse() {
   374→                        Ok(pk) => pk,
   375→                        Err(e) => {
   376→                            warn!(
   377→                                "Failed to parse {} pubkey '{}': {}, skipping schedule computation",
   378→                                if is_v2_tree { "merkle tree" } else { "queue" },
   379→                                seed_pubkey_str,
   380→                                e
   381→                            );
   382→                            continue;
   383→                        }
   384→                    };
   385→                    let mut schedule: Vec<Option<usize>> =
   386→                        Vec::with_capacity(total_light_slots as usize);
   387→
   388→                    for light_slot_idx in 0..total_light_slots {
   389→                        let forester_idx = ForesterEpochPda::get_eligible_forester_index(
   390→                            light_slot_idx,
   391→                            &seed_pubkey,
   392→                            total_epoch_weight,
   393→                            current_active_epoch,
   394→                        )
   395→                        .ok()
   396→                        .and_then(|eligible_idx| {
   397→                            active_epoch_forester_pdas
   398→                                .iter()
   399→                                .find(|pda| pda.is_eligible(eligible_idx))
   400→                                .and_then(|pda| authority_to_index.get(&pda.authority.to_string()))
   401→                                .copied()
   402→                        });
   403→                        schedule.push(forester_idx);
   404→                    }
   405→
   406→                    // Set current assigned forester
   407→                    if let Some(current_idx) = current_light_slot {
   408→                        if let Some(Some(forester_idx)) = schedule.get(current_idx as usize) {
   409→                            status.assigned_forester =
   410→                                Some(active_epoch_foresters[*forester_idx].authority.clone());
   411→                        }
   412→                    }
   413→
   414→                    status.schedule = schedule;
   415→                }
   416→            }
   417→        }
   418→    }
   419→
   420→    // Compute aggregate statistics from tree statuses
   421→    let total_trees = tree_statuses.len();
   422→    let active_trees = tree_statuses.iter().filter(|t| !t.is_rolledover).count();
   423→    let rolled_over_trees = tree_statuses.iter().filter(|t| t.is_rolledover).count();
   424→    let total_pending_items: u64 = tree_statuses.iter().filter_map(|t| t.queue_length).sum();
   425→
   426→    let mut aggregate_queue_stats = AggregateQueueStats {
   427→        state_v1_total_pending: 0,
   428→        state_v2_input_pending: 0,
   429→        state_v2_output_pending: 0,
   430→        address_v1_total_pending: 0,
   431→        address_v2_input_pending: 0,
   432→        state_v2_input_pending_batches: 0,
   433→        state_v2_output_pending_batches: 0,
   434→        address_v2_input_pending_batches: 0,
   435→    };
   436→
   437→    for t in &tree_statuses {
   438→        match t.tree_type.as_str() {
   439→            "StateV1" => {
   440→                aggregate_queue_stats.state_v1_total_pending += t.queue_length.unwrap_or(0);
   441→            }
   442→            "StateV2" => {
   443→                if let Some(ref info) = t.v2_queue_info {
   444→                    aggregate_queue_stats.state_v2_input_pending +=
   445→                        info.input_pending_batches * info.zkp_batch_size;
   446→                    aggregate_queue_stats.state_v2_output_pending +=
   447→                        info.output_pending_batches * info.zkp_batch_size;
   448→                    aggregate_queue_stats.state_v2_input_pending_batches +=
   449→                        info.input_pending_batches;
   450→                    aggregate_queue_stats.state_v2_output_pending_batches +=
   451→                        info.output_pending_batches;
   452→                }
   453→            }
   454→            "AddressV1" => {
   455→                aggregate_queue_stats.address_v1_total_pending += t.queue_length.unwrap_or(0);
   456→            }
   457→            "AddressV2" => {
   458→                if let Some(ref info) = t.v2_queue_info {
   459→                    aggregate_queue_stats.address_v2_input_pending +=
   460→                        info.input_pending_batches * info.zkp_batch_size;
   461→                    aggregate_queue_stats.address_v2_input_pending_batches +=
   462→                        info.input_pending_batches;
   463→                }
   464→            }
   465→            _ => {}
   466→        }
   467→    }
   468→
   469→    let total_pending_batches = aggregate_queue_stats.state_v2_input_pending_batches
   470→        + aggregate_queue_stats.state_v2_output_pending_batches
   471→        + aggregate_queue_stats.address_v2_input_pending_batches;
   472→
   473→    Ok(ForesterStatus {
   474→        slot,
   475→        current_active_epoch,
   476→        current_registration_epoch,
   477→        active_epoch_progress,
   478→        active_phase_length,
   479→        active_epoch_progress_percentage,
   480→        hours_until_next_epoch,
   481→        registration_is_open,
   482→        slots_until_next_registration,
   483→        hours_until_next_registration,
   484→        active_epoch_foresters,
   485→        registration_epoch_foresters,
   486→        trees: tree_statuses,
   487→        current_light_slot,
   488→        light_slot_length,
   489→        slots_until_next_light_slot,
   490→        total_light_slots,
   491→        total_trees,
   492→        active_trees,
   493→        rolled_over_trees,
   494→        total_pending_batches,
   495→        total_pending_items,
   496→        aggregate_queue_stats,
   497→    })
   498→}
