   500→async fn fetch_registry_accounts_filtered<R: Rpc>(
   501→    rpc: &R,
   502→) -> crate::Result<(Vec<ForesterEpochPda>, Vec<EpochPda>, Vec<ProtocolConfigPda>)> {
   503→    let program_id = light_registry::ID;
   504→
   505→    // Use try_join! to propagate RPC errors instead of silently returning empty data
   506→    let (forester_accounts, epoch_accounts, config_accounts) = tokio::try_join!(
   507→        rpc.get_program_accounts_with_discriminator(&program_id, ForesterEpochPda::DISCRIMINATOR),
   508→        rpc.get_program_accounts_with_discriminator(&program_id, EpochPda::DISCRIMINATOR),
   509→        rpc.get_program_accounts_with_discriminator(&program_id, ProtocolConfigPda::DISCRIMINATOR),
   510→    )
   511→    .context("Failed to fetch registry program accounts")?;
   512→
   513→    let mut forester_epoch_pdas = Vec::new();
   514→    let mut epoch_pdas = Vec::new();
   515→    let mut protocol_config_pdas = Vec::new();
   516→
   517→    for (_, account) in forester_accounts {
   518→        let mut data: &[u8] = &account.data;
   519→        if let Ok(pda) = ForesterEpochPda::try_deserialize_unchecked(&mut data) {
   520→            forester_epoch_pdas.push(pda);
   521→        }
   522→    }
   523→
   524→    for (_, account) in epoch_accounts {
   525→        let mut data: &[u8] = &account.data;
   526→        if let Ok(pda) = EpochPda::try_deserialize_unchecked(&mut data) {
   527→            epoch_pdas.push(pda);
   528→        }
   529→    }
   530→
   531→    for (_, account) in config_accounts {
   532→        let mut data: &[u8] = &account.data;
   533→        if let Ok(pda) = ProtocolConfigPda::try_deserialize_unchecked(&mut data) {
   534→            protocol_config_pdas.push(pda);
   535→        }
   536→    }
   537→
   538→    forester_epoch_pdas.sort_by(|a, b| a.epoch.cmp(&b.epoch));
   539→    epoch_pdas.sort_by(|a, b| a.epoch.cmp(&b.epoch));
   540→
   541→    Ok((forester_epoch_pdas, epoch_pdas, protocol_config_pdas))
   542→}
