   544→async fn fetch_tree_statuses_batched<R: Rpc>(rpc: &R, trees: &[TreeAccounts]) -> Vec<TreeStatus> {
   545→    if trees.is_empty() {
   546→        return vec![];
   547→    }
   548→
   549→    let mut pubkeys: Vec<Pubkey> = Vec::with_capacity(trees.len() * 2);
   550→    let mut pubkey_map: Vec<(usize, &str)> = Vec::with_capacity(trees.len() * 2);
   551→
   552→    for (i, tree) in trees.iter().enumerate() {
   553→        pubkeys.push(tree.merkle_tree);
   554→        pubkey_map.push((i, "merkle_tree"));
   555→
   556→        if tree.tree_type != TreeType::AddressV2 {
   557→            pubkeys.push(tree.queue);
   558→            pubkey_map.push((i, "queue"));
   559→        }
   560→    }
   561→
   562→    let accounts = match rpc.get_multiple_accounts(&pubkeys).await {
   563→        Ok(accounts) => accounts,
   564→        Err(e) => {
   565→            tracing::warn!("Failed to batch fetch accounts: {:?}", e);
   566→            return vec![];
   567→        }
   568→    };
   569→
   570→    let mut tree_accounts: Vec<(Option<Account>, Option<Account>)> =
   571→        vec![(None, None); trees.len()];
   572→
   573→    for (idx, (tree_idx, account_type)) in pubkey_map.iter().enumerate() {
   574→        if let Some(Some(account)) = accounts.get(idx) {
   575→            match *account_type {
   576→                "merkle_tree" => tree_accounts[*tree_idx].0 = Some(account.clone()),
   577→                "queue" => tree_accounts[*tree_idx].1 = Some(account.clone()),
   578→                _ => {}
   579→            }
   580→        }
   581→    }
   582→
   583→    let mut tree_statuses = Vec::with_capacity(trees.len());
   584→
   585→    for (i, tree) in trees.iter().enumerate() {
   586→        let (merkle_account, queue_account) = &tree_accounts[i];
   587→
   588→        match parse_tree_status(tree, merkle_account.clone(), queue_account.clone()) {
   589→            Ok(status) => tree_statuses.push(status),
   590→            Err(e) => {
   591→                tracing::warn!(
   592→                    "Failed to parse tree status for {}: {:?}",
   593→                    tree.merkle_tree,
   594→                    e
   595→                );
   596→            }
   597→        }
   598→    }
   599→
   600→    tree_statuses
   601→}
   602→
   603→async fn fetch_forester_balances<R: Rpc>(
   604→    rpc: &R,
   605→    pubkeys: &[Pubkey],
   606→) -> HashMap<Pubkey, Option<f64>> {
   607→    let mut balances = HashMap::new();
   608→
   609→    if pubkeys.is_empty() {
   610→        return balances;
   611→    }
   612→
   613→    match rpc.get_multiple_accounts(pubkeys).await {
   614→        Ok(accounts) => {
   615→            for (i, account_opt) in accounts.iter().enumerate() {
   616→                if let Some(pubkey) = pubkeys.get(i) {
   617→                    let balance = account_opt
   618→                        .as_ref()
   619→                        .map(|acc| acc.lamports as f64 / 1_000_000_000.0);
   620→                    balances.insert(*pubkey, balance);
   621→                }
   622→            }
   623→        }
   624→        Err(e) => {
   625→            tracing::warn!("Failed to fetch forester balances: {:?}", e);
   626→            for pubkey in pubkeys {
   627→                balances.insert(*pubkey, None);
   628→            }
   629→        }
   630→    }
   631→
   632→    balances
   633→}
   634→
   635→fn parse_tree_status(
   636→    tree: &TreeAccounts,
   637→    merkle_account: Option<Account>,
   638→    queue_account: Option<Account>,
   639→) -> crate::Result<TreeStatus> {
   640→    let mut merkle_account =
   641→        merkle_account.ok_or_else(|| anyhow::anyhow!("Merkle tree account not found"))?;
   642→
   643→    let (
   644→        fullness_percentage,
   645→        next_index,
   646→        capacity,
   647→        height,
   648→        threshold,
   649→        queue_length,
   650→        queue_capacity,
   651→        v2_queue_info,
   652→    ) = match tree.tree_type {
   653→        TreeType::StateV1 => {
   654→            let tree_account = StateMerkleTreeAccount::deserialize(&mut &merkle_account.data[8..])
   655→                .map_err(|e| anyhow::anyhow!("Failed to deserialize StateV1 metadata: {}", e))?;
   656→
   657→            let height = STATE_MERKLE_TREE_HEIGHT;
   658→            let capacity = 1u64 << height;
   659→            let threshold_val = capacity
   660→                .saturating_mul(tree_account.metadata.rollover_metadata.rollover_threshold)
   661→                / 100;
   662→
   663→            let merkle_tree =
   664→                parse_concurrent_merkle_tree_from_bytes::<StateMerkleTreeAccount, Poseidon, 26>(
   665→                    &merkle_account.data,
   666→                )
   667→                .map_err(|e| anyhow::anyhow!("Failed to parse StateV1 tree: {:?}", e))?;
   668→
   669→            let next_index = merkle_tree.next_index() as u64;
   670→            let fullness = next_index as f64 / capacity as f64 * 100.0;
   671→
   672→            let (queue_len, queue_cap) = queue_account
   673→                .map(|acc| {
   674→                    unsafe { parse_hash_set_from_bytes::<QueueAccount>(&acc.data) }
   675→                        .ok()
   676→                        .map(|hs| {
   677→                            let len = hs
   678→                                .iter()
   679→                                .filter(|(_, cell)| cell.sequence_number.is_none())
   680→                                .count() as u64;
   681→                            let cap = hs.get_capacity() as u64;
   682→                            (len, cap)
   683→                        })
   684→                        .unwrap_or((0, 0))
   685→                })
   686→                .map(|(l, c)| (Some(l), Some(c)))
   687→                .unwrap_or((None, None));
   688→
   689→            (
   690→                fullness,
   691→                next_index,
   692→                capacity,
   693→                height as u32,
   694→                threshold_val,
   695→                queue_len,
   696→                queue_cap,
   697→                None,
   698→            )
   699→        }
   700→        TreeType::AddressV1 => {
   701→            let height = ADDRESS_MERKLE_TREE_HEIGHT;
   702→            let capacity = 1u64 << height;
   703→
   704→            let threshold_val = queue_account
   705→                .as_ref()
   706→                .and_then(|acc| QueueAccount::deserialize(&mut &acc.data[8..]).ok())
   707→                .map(|q| {
   708→                    capacity.saturating_mul(q.metadata.rollover_metadata.rollover_threshold) / 100
   709→                })
   710→                .unwrap_or(0);
   711→
   712→            let merkle_tree = parse_indexed_merkle_tree_from_bytes::<
   713→                AddressMerkleTreeAccount,
   714→                Poseidon,
   715→                usize,
   716→                26,
   717→                16,
   718→            >(&merkle_account.data)
   719→            .map_err(|e| anyhow::anyhow!("Failed to parse AddressV1 tree: {:?}", e))?;
   720→
   721→            let next_index = merkle_tree
   722→                .next_index()
   723→                .saturating_sub(INDEXED_MERKLE_TREE_V1_INITIAL_LEAVES)
   724→                as u64;
   725→            let fullness = next_index as f64 / capacity as f64 * 100.0;
   726→
   727→            let (queue_len, queue_cap) = queue_account
   728→                .map(|acc| {
   729→                    unsafe { parse_hash_set_from_bytes::<QueueAccount>(&acc.data) }
   730→                        .ok()
   731→                        .map(|hs| {
   732→                            let len = hs
   733→                                .iter()
   734→                                .filter(|(_, cell)| cell.sequence_number.is_none())
   735→                                .count() as u64;
   736→                            let cap = hs.get_capacity() as u64;
   737→                            (len, cap)
   738→                        })
   739→                        .unwrap_or((0, 0))
   740→                })
   741→                .map(|(l, c)| (Some(l), Some(c)))
   742→                .unwrap_or((None, None));
   743→
   744→            (
   745→                fullness,
   746→                next_index,
   747→                capacity,
   748→                height as u32,
   749→                threshold_val,
   750→                queue_len,
   751→                queue_cap,
   752→                None,
   753→            )
   754→        }
   755→        TreeType::StateV2 => {
   756→            let merkle_tree = BatchedMerkleTreeAccount::state_from_bytes(
   757→                &mut merkle_account.data,
   758→                &tree.merkle_tree.into(),
   759→            )
   760→            .map_err(|e| anyhow::anyhow!("Failed to parse StateV2 tree: {:?}", e))?;
   761→
   762→            let height = merkle_tree.height as u64;
   763→            let capacity = 1u64 << height;
   764→            let threshold_val =
   765→                (1u64 << height) * merkle_tree.metadata.rollover_metadata.rollover_threshold / 100;
   766→            let next_index = merkle_tree.next_index;
   767→            let fullness = next_index as f64 / capacity as f64 * 100.0;
   768→
   769→            let v2_info = queue_account
   770→                .and_then(|mut acc| parse_state_v2_queue_info(&merkle_tree, &mut acc.data).ok());
   771→            let queue_len = v2_info
   772→                .as_ref()
   773→                .map(|i| (i.input_pending_batches + i.output_pending_batches) * i.zkp_batch_size);
   774→            let queue_cap = v2_info
   775→                .as_ref()
   776→                .map(|i| i.batches.len() as u64 * i.batch_size);
   777→
   778→            (
   779→                fullness,
   780→                next_index,
   781→                capacity,
   782→                height as u32,
   783→                threshold_val,
   784→                queue_len,
   785→                queue_cap,
   786→                v2_info,
   787→            )
   788→        }
   789→        TreeType::AddressV2 => {
   790→            let merkle_tree = BatchedMerkleTreeAccount::address_from_bytes(
   791→                &mut merkle_account.data,
   792→                &tree.merkle_tree.into(),
   793→            )
   794→            .map_err(|e| anyhow::anyhow!("Failed to parse AddressV2 tree: {:?}", e))?;
   795→
   796→            let height = merkle_tree.height as u64;
   797→            let capacity = 1u64 << height;
   798→            let threshold_val =
   799→                capacity * merkle_tree.metadata.rollover_metadata.rollover_threshold / 100;
   800→            let fullness = merkle_tree.next_index as f64 / capacity as f64 * 100.0;
   801→
   802→            let v2_info = parse_address_v2_queue_info(&merkle_tree);
   803→            let queue_len = Some(v2_info.input_pending_batches * v2_info.zkp_batch_size);
   804→            let queue_cap = Some(v2_info.batches.len() as u64 * v2_info.batch_size);
   805→
   806→            (
   807→                fullness,
   808→                merkle_tree.next_index,
   809→                capacity,
   810→                height as u32,
   811→                threshold_val,
   812→                queue_len,
   813→                queue_cap,
   814→                Some(v2_info),
   815→            )
   816→        }
   817→        TreeType::Unknown => {
   818→            warn!(
   819→                "Encountered unknown tree type for merkle_tree={}, queue={}",
   820→                tree.merkle_tree, tree.queue
   821→            );
   822→            (0.0, 0, 0, 0, 0, None, None, None)
   823→        }
   824→    };
   825→
   826→    Ok(TreeStatus {
   827→        tree_type: tree.tree_type.to_string(),
   828→        merkle_tree: tree.merkle_tree.to_string(),
   829→        queue: tree.queue.to_string(),
   830→        fullness_percentage,
   831→        next_index,
   832→        capacity,
   833→        height,
   834→        threshold,
   835→        is_rolledover: tree.is_rolledover,
   836→        queue_length,
   837→        queue_capacity,
   838→        v2_queue_info,
   839→        assigned_forester: None,
   840→        schedule: Vec::new(),
   841→        owner: tree.owner.to_string(),
   842→    })
   843→}
   844→
   845→pub async fn fetch_forester_status(args: &StatusArgs) -> crate::Result<()> {
   846→    let commitment_config = CommitmentConfig::confirmed();
   847→
   848→    let client = solana_client::rpc_client::RpcClient::new_with_commitment(
   849→        args.rpc_url.clone(),
   850→        commitment_config,
   851→    );
   852→    let registry_accounts = client
   853→        .get_program_accounts(&light_registry::ID)
   854→        .context("Failed to fetch accounts for registry program")?;
   855→
   856→    let mut forester_epoch_pdas = vec![];
   857→    let mut epoch_pdas = vec![];
   858→    let mut protocol_config_pdas = vec![];
   859→    for (_, account) in registry_accounts {
   860→        let discriminator_bytes = match account.data().get(0..8) {
   861→            Some(d) => d,
   862→            None => continue,
