  1097→
  1098→fn print_current_forester_assignments(
  1099→    slot: Slot,
  1100→    current_active_epoch: u64,
  1101→    active_epoch_foresters: Vec<ForesterEpochPda>,
  1102→    trees: &Vec<TreeAccounts>,
  1103→    current_epoch_pda_entry: Option<&EpochPda>,
  1104→    protocol_config: &ProtocolConfigPda,
  1105→) {
  1106→    if let Some(_current_epoch_pda) = current_epoch_pda_entry {
  1107→        if active_epoch_foresters.is_empty() {
  1108→            println!(
  1109→                "error: no foresters registered for active epoch {}",
  1110→                current_active_epoch
  1111→            );
  1112→            return;
  1113→        }
  1114→
  1115→        let total_epoch_weight = match active_epoch_foresters
  1116→            .first()
  1117→            .and_then(|pda| pda.total_epoch_weight)
  1118→        {
  1119→            Some(w) if w > 0 => w,
  1120→            _ => {
  1121→                println!(
  1122→                    "error: registration not finalized (total_epoch_weight is none or 0) for epoch {}",
  1123→                    current_active_epoch
  1124→                );
  1125→                return;
  1126→            }
  1127→        };
  1128→
  1129→        let epoch_phases = get_epoch_phases(&protocol_config.config, current_active_epoch);
  1130→
  1131→        if slot < epoch_phases.active.start || slot >= epoch_phases.active.end {
  1132→            println!(
  1133→                "Info: Not currently within the active phase of epoch {}.",
  1134→                current_active_epoch
  1135→            );
  1136→            return;
  1137→        }
  1138→
  1139→        if protocol_config.config.slot_length == 0 {
  1140→            println!("error: protocol config slot_length is zero; cannot calculate light slots");
  1141→            return;
  1142→        }
  1143→
  1144→        let current_light_slot_index =
  1145→            (slot - epoch_phases.active.start) / protocol_config.config.slot_length;
  1146→        let start_solana_slot_of_current_light_slot = epoch_phases.active.start
  1147→            + current_light_slot_index * protocol_config.config.slot_length;
  1148→        let end_solana_slot_of_current_light_slot =
  1149→            start_solana_slot_of_current_light_slot + protocol_config.config.slot_length;
  1150→
  1151→        let slots_remaining_in_light_slot =
  1152→            end_solana_slot_of_current_light_slot.saturating_sub(slot);
  1153→        let time_remaining_secs = slots_remaining_in_light_slot as f64 * 0.460;
  1154→
  1155→        println!(
  1156→            "Current Light Slot Index: {} (Solana slots {}-{}, Approx. {:.2}s remaining)",
  1157→            current_light_slot_index,
  1158→            start_solana_slot_of_current_light_slot,
  1159→            end_solana_slot_of_current_light_slot - 1,
  1160→            time_remaining_secs
  1161→        );
  1162→
  1163→        println!("Queue processors for the current light slot:");
  1164→        println!("Tree Type\t\tTree Address\tForester");
  1165→
  1166→        for tree in trees {
  1167→            let eligible_forester_slot_index = match ForesterEpochPda::get_eligible_forester_index(
  1168→                current_light_slot_index,
  1169→                &tree.queue,
  1170→                total_epoch_weight,
  1171→                current_active_epoch,
  1172→            ) {
  1173→                Ok(idx) => idx,
  1174→                Err(e) => {
  1175→                    println!(
  1176→                        "{:12}\t\t{}\terror: {:?}",
  1177→                        tree.tree_type, tree.merkle_tree, e
  1178→                    );
  1179→                    continue;
  1180→                }
  1181→            };
  1182→
  1183→            let assigned_forester = active_epoch_foresters
  1184→                .iter()
  1185→                .find(|pda| pda.is_eligible(eligible_forester_slot_index));
  1186→
  1187→            if let Some(forester_pda) = assigned_forester {
  1188→                println!(
  1189→                    "{:12}\t\t{}\t{}",
  1190→                    tree.tree_type, tree.merkle_tree, forester_pda.authority
  1191→                );
  1192→            } else {
  1193→                println!(
  1194→                    "{:12}\t\t{}\tUNASSIGNED (Eligible Index: {})",
  1195→                    tree.tree_type, tree.merkle_tree, eligible_forester_slot_index
  1196→                );
  1197→            }
  1198→        }
  1199→    } else {
  1200→        println!(
  1201→            "error: could not find EpochPda for active epoch {}; cannot determine forester assignments",
  1202→            current_active_epoch
  1203→        );
  1204→    }
  1205→}
