  1207→fn print_tree_schedule_by_forester(
  1208→    slot: Slot,
  1209→    current_active_epoch: u64,
  1210→    active_epoch_foresters: Vec<ForesterEpochPda>,
  1211→    tree: Pubkey,
  1212→    queue: Pubkey,
  1213→    current_epoch_pda_entry: Option<&EpochPda>,
  1214→    protocol_config: &ProtocolConfigPda,
  1215→) {
  1216→    if let Some(_current_epoch_pda) = current_epoch_pda_entry {
  1217→        if active_epoch_foresters.is_empty() {
  1218→            println!(
  1219→                "error: no foresters registered for tree {} in active epoch {}",
  1220→                tree, current_active_epoch
