  1226→            {
  1227→                Some(w) if w > 0 => w,
  1228→                _ => {
  1229→                    println!(
  1230→                        "error: registration not finalized (total_epoch_weight is none or 0) for epoch {}; cannot check assignments",
  1231→                        current_active_epoch
  1232→                    );
  1233→                    0
  1234→                }
  1235→            };
