  1239→
  1240→                if slot >= epoch_phases.active.start && slot < epoch_phases.active.end {
  1241→                    if protocol_config.config.slot_length > 0 {
  1242→                        let current_light_slot_index =
  1243→                            (slot - epoch_phases.active.start) / protocol_config.config.slot_length;
  1244→                        let start_solana_slot_of_current_light_slot = epoch_phases.active.start
  1245→                            + current_light_slot_index * protocol_config.config.slot_length;
  1246→                        let end_solana_slot_of_current_light_slot =
