    97→#[derive(Debug, Default, Clone, PartialEq, Eq)]
    98→pub enum EpochState {
    99→    Registration,
   100→    Active,
   101→    ReportWork,
   102→    Post,
   103→    #[default]
   104→    Pre,
   105→}
   106→
   107→/// Light Epoch Example:
   108→///
   109→///  Diagram of epochs 0 and 1.
   110→/// Registration 0 starts at genesis slot.
   111→/// |---- Registration 0 ----|------------------ Active 0 ------|---- Report Work 0 ----|---- Post 0 ----
   112→///                                        |-- Registration 1 --|------------------ Active 1 -----------------
   113→/// (Post epoch does not end unlike the other phases.)
   114→///
   115→/// let genesis = 0;
   116→/// let registration_phase_length = 100;
   117→/// let active_phase_length = 1000;
   118→/// let report_work_phase_length = 100;
   119→/// let slot = 10;
   120→///
   121→/// To get the latest registry epoch:
   122→/// - slot = 0;
   123→///   let current_registry_epoch = (slot - genesis) / active_phase_length;
   124→///   current_registry_epoch =  (0 - 0) / 1000 = 0;
   125→///   first active phase starts at genesis + registration_phase_length
   126→///   = 0 + 100 = 100;
   127→///
   128→/// To get the current active epoch:
   129→/// - slot = 100;
   130→///   let current_active_epoch =
   131→///   (slot - genesis - registration_phase_length) / active_phase_length;
   132→///   current_active_epoch = (100 - 0 - 100) / 1000 = 0;
   133→///
   134→/// Epoch 0:
   135→/// - Registration 0: 0 - 100
   136→/// - Active 0: 100 - 1100
   137→/// - Report Work 0: 1100 - 1200
   138→/// - Post 0: 1200 - inf
   139→///
   140→/// Epoch 1:
   141→/// - Registration 1: 1000 - 1100
   142→/// - Active 1: 1100 - 2100
   143→/// - Report Work 1: 2100 - 2200
   144→/// - Post 1: 2200 - inf
   145→///
   146→/// Epoch 2:
   147→/// - Registration 2: 2000 - 2100
   148→/// - Active 2: 2100 - 3100
   149→/// - Report Work 2: 3100 - 3200
   150→/// - Post 2: 3200 - inf
   151→///
   152→impl ProtocolConfig {
   153→    /// Current epoch including registration phase.
   154→    pub fn get_latest_register_epoch(&self, slot: u64) -> Result<u64> {
   155→        let slot = slot
   156→            .checked_sub(self.genesis_slot)
   157→            .ok_or(RegistryError::GetLatestRegisterEpochFailed)?;
   158→        Ok(slot / self.active_phase_length)
   159→    }
   160→
   161→    pub fn get_current_epoch(&self, slot: u64) -> u64 {
   162→        (slot.saturating_sub(self.genesis_slot)) / self.active_phase_length
   163→    }
   164→
   165→    pub fn get_current_active_epoch(&self, slot: u64) -> Result<u64> {
   166→        let slot = slot
   167→            .checked_sub(self.genesis_slot + self.registration_phase_length)
   168→            .ok_or(RegistryError::GetCurrentActiveEpochFailed)?;
   169→        Ok(slot / self.active_phase_length)
   170→    }
   171→
   172→    pub fn get_latest_register_epoch_progress(&self, slot: u64) -> Result<u64> {
   173→        Ok(slot
   174→            .checked_sub(self.genesis_slot)
   175→            .ok_or(RegistryError::ArithmeticUnderflow)?
   176→            % self.active_phase_length)
   177→    }
   178→
   179→    pub fn get_current_active_epoch_progress(&self, slot: u64) -> u64 {
   180→        slot.checked_sub(self.genesis_slot + self.registration_phase_length)
   181→            .map(|s| s % self.active_phase_length)
   182→            .unwrap_or(0)
   183→    }
   184→
   185→    /// In the last part of the active phase the registration phase starts.
   186→    /// Returns end slot of the registration phase/start slot of the next active phase.
   187→    /// Registration phase time check is temporarily disabled to allow
   188→    /// foresters to register for the current epoch at any time.        
   189→    pub fn is_registration_phase(&self, slot: u64) -> Result<u64> {
   190→        let latest_register_epoch = self.get_latest_register_epoch(slot)?;
   191→        /*
   192→        let latest_register_epoch_progress = self.get_latest_register_epoch_progress(slot)?;
   193→        if latest_register_epoch_progress >= self.registration_phase_length {
   194→            return err!(RegistryError::NotInRegistrationPeriod);
   195→        } */
   196→
   197→        Ok((latest_register_epoch) * self.active_phase_length
   198→            + self.genesis_slot
   199→            + self.registration_phase_length)
   200→    }
   201→
   202→    pub fn is_active_phase(&self, slot: u64, epoch: u64) -> Result<()> {
   203→        if self.get_current_active_epoch(slot)? != epoch {
   204→            return err!(RegistryError::NotInActivePhase);
   205→        }
   206→        Ok(())
   207→    }
   208→
   209→    pub fn is_report_work_phase(&self, slot: u64, epoch: u64) -> Result<()> {
   210→        self.is_active_phase(slot, epoch + 1)?;
   211→        let current_epoch_progress = self.get_current_active_epoch_progress(slot);
   212→        if current_epoch_progress >= self.report_work_phase_length {
   213→            return err!(RegistryError::NotInReportWorkPhase);
   214→        }
   215→        Ok(())
   216→    }
   217→
   218→    pub fn is_post_epoch(&self, slot: u64, epoch: u64) -> Result<()> {
   219→        if self.get_current_active_epoch(slot)? <= epoch {
   220→            return err!(RegistryError::InvalidEpoch);
   221→        }
   222→        Ok(())
   223→    }
   224→}
