use anyhow::Result;
use chrono::Utc;
use clap::Parser;
use solana_client::rpc_client::{GetConfirmedSignaturesForAddress2Config, RpcClient};
use solana_sdk::{commitment_config::CommitmentConfig, pubkey::Pubkey, signature::Signature};
use std::str::FromStr;
use tabled::{builder::Builder, settings::Style};

#[derive(Debug, Parser)]
pub struct Options {
    /// One or more base58 public keys (positional, space-separated)
    #[clap(required = true)]
    pubkeys: Vec<String>,

    /// Bucket size in minutes
    #[clap(long, default_value_t = 10)]
    minutes: u64,

    /// Number of buckets to show going back in time
    #[clap(long, default_value_t = 6)]
    buckets: u64,

    /// Network: mainnet | devnet | testnet | local
    #[clap(long, default_value = "mainnet")]
    network: String,

    /// Custom RPC URL (overrides --network)
    #[clap(long)]
    rpc_url: Option<String>,
}

fn network_to_url(network: &str) -> String {
    match network {
        "mainnet" => "https://api.mainnet-beta.solana.com".to_string(),
        "devnet" => "https://api.devnet.solana.com".to_string(),
        "testnet" => "https://api.testnet.solana.com".to_string(),
        "local" | "localnet" => "http://localhost:8899".to_string(),
        custom => custom.to_string(),
    }
}

fn shorten_address(addr: &str) -> String {
    if addr.len() > 10 {
        format!("{}...{}", &addr[..6], &addr[addr.len() - 3..])
    } else {
        addr.to_string()
    }
}

pub async fn fetch_keypair_txs(opts: Options) -> Result<()> {
    let rpc_url = opts
        .rpc_url
        .unwrap_or_else(|| network_to_url(&opts.network));

    println!(
        "Fetching transactions for {} address(es)  |  bucket: {} min  |  looking back {} buckets",
        opts.pubkeys.len(),
        opts.minutes,
        opts.buckets
    );
    println!("RPC: {}", rpc_url);
    println!();

    let client = RpcClient::new_with_commitment(rpc_url, CommitmentConfig::confirmed());

    let now = Utc::now().timestamp();
    let bucket_secs = opts.minutes as i64 * 60;
    let total_lookback = bucket_secs * opts.buckets as i64;
    let cutoff = now - total_lookback;

    // Build header: Address, -10m, TPS, -20m, TPS, ..., Total
    let mut header = vec!["Address".to_string()];
    for k in 1..=opts.buckets {
        header.push(format!("-{}m", k * opts.minutes));
        header.push("TPS".to_string());
    }
    header.push("Total".to_string());

    let mut builder = Builder::default();
    builder.push_record(header);

    for pubkey_str in &opts.pubkeys {
        let pubkey = Pubkey::from_str(pubkey_str)?;

        // Paginate until the oldest returned sig is beyond the cutoff.
        let mut counts = vec![0u64; opts.buckets as usize];
        let mut before: Option<Signature> = None;
        loop {
            let batch = client.get_signatures_for_address_with_config(
                &pubkey,
                GetConfirmedSignaturesForAddress2Config {
                    before,
                    limit: Some(1000),
                    commitment: Some(CommitmentConfig::confirmed()),
                    ..Default::default()
                },
            )?;

            let exhausted = batch.len() < 1000;
            let mut reached_cutoff = false;

            for sig_info in &batch {
                if let Some(block_time) = sig_info.block_time {
                    if block_time < cutoff {
                        reached_cutoff = true;
                        continue;
                    }
                    // Bucket 0 = most recent [now - bucket_secs, now)
                    let age = now - block_time;
                    let bucket_idx = if age < 0 {
                        0
                    } else {
                        (age / bucket_secs) as usize
                    };
                    if bucket_idx < opts.buckets as usize {
                        counts[bucket_idx] += 1;
                    }
                }
            }

            if exhausted || reached_cutoff {
                break;
            }

            // Advance cursor to the last (oldest) signature in this batch.
            match batch.last() {
                Some(last) => before = Some(Signature::from_str(&last.signature)?),
                None => break,
            }
        }

        let total: u64 = counts.iter().sum();

        let mut row = vec![shorten_address(pubkey_str)];
        for count in &counts {
            row.push(count.to_string());
            let tps = *count as f64 / bucket_secs as f64;
            row.push(format!("{:.3}", tps));
        }
        row.push(total.to_string());

        builder.push_record(row);
    }

    let table = builder.build().with(Style::rounded()).to_string();
    println!("{}", table);

    Ok(())
}

